#include<bits/stdc++.h>
using namespace std;
long long a[105][105],ans=INT_MAX,n,m,dp[105][105];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
			if(i!=j) dp[i][j]=a[i][j]=INT_MAX;
    for(int i=1;i<=m;i++){
        long long x,y,z;
        cin>>x>>y>>z;
        a[x][y]=min(z,a[x][y]);
        a[y][x]=min(z,a[y][x]);
        dp[x][y]=a[x][y];
        dp[y][x]=a[y][x];
    }
    for(int k=1;k<=n;k++){
        for(int i=1;i<k;i++){
            for(int j=i+1;j<k;j++){
                long long cns=dp[i][j]+a[k][i]+a[j][k];
                ans=min(ans,cns);
            }
        }
        for(int i=1;i<=n;i++){
            for(int j=1;j<=n;j++){
                dp[i][j] = min(dp[i][j],dp[i][k]+dp[k][j]);
				dp[j][i] = dp[i][j];
            }
        }
    }
    if(ans==INT_MAX) cout<<"No solution.";
    else cout<<ans;
    return 0;
}
